script:
export const meta = {
  name: 'claudex-plan-review-fanout',
  description: 'Pass-2 parallel reviewer fan-out over the claudex-integration plan',
  phases: [{ title: 'Review', detail: 'six plan-aware reviewers in parallel' }],
}

const PLAN = '/Users/ernie/.claude/plans/claudex-integration.md'
const BRAINSTORM = '/Users/ernie/.claude/brainstorms/claudex-integration.md'

const COMMON = `Review the plan file at ${PLAN} (pass 1). Context doc (operator handoff, decisions LOCKED): ${BRAINSTORM}.

Ground your review in the actual code when you make factual claims: the olam monorepo worktree is at /Users/ernie/Projects/pleri-org/olam-wt/claudex-plan (relevant: packages/auth-worker/src/, packages/auth-client/src/) and the cockpit repo at /Users/ernie/Projects/claude-cockpit (server.js, lib/).

INTENT-RESPECT (hard rule): these operator decisions are LOCKED — do NOT relitigate them or file findings that amount to questioning them: (1) approach Y = Claude Code harness backed by Codex, not codex-CLI spawn; (2) translator hosted in auth-worker, no per-machine proxy; (3) credential = billed OpenAI API key on api.openai.com/v1/responses, ChatGPT-subscription OAuth stays sandbox-only; (4) Claudex primary, codex CLI/RPC demoted-but-kept. Surface gaps in HOW, never WHY. If a finding could be answered with "yes, the operator wants it", drop it.

PROBABILITY LENS: every finding carries severity (P0=plan-breaking, P1=major, P2=moderate, P3=minor) AND likelihood (likely|possible|unlikely|remote). Do not inflate: a P0 with likelihood=remote is not load-bearing. When unsure of likelihood, default to likely.

Return ONLY findings that would change what the implementer does. No style nits on plan prose.`

const REVIEWERS = [
  { key: 'coherence', type: 'plan-coherence-reviewer', extra: 'Focus: internal consistency — contradictions between sections, terminology drift, ambiguity where two implementers would diverge.' },
  { key: 'feasibility', type: 'plan-feasibility-reviewer', extra: 'Focus: will the approach survive contact with reality — verify the cited file:line seams exist and support what the plan claims, dependency gaps, implementability of Phase A translator + detection seam + credential carve-out, and Phase B tmux -e env injection. Attack OQ1 (in-worker TransformStream SSE re-encode viability within Cloudflare Workers limits) hard: is the plan\'s promotion argument sound?' },
  { key: 'scope', type: 'plan-scope-guardian-reviewer', extra: 'Focus: scope alignment + unjustified complexity — anything exceeding the stated goal, premature abstraction, or missing-but-required scope. The tier is feature per operator direction; flag only if scope GENUINELY demands epic (B3 schema gate or translator ballooning).' },
  { key: 'patterns', type: 'plan-pattern-references-reviewer', extra: 'Focus: verify every entry in "## Existing patterns referenced" is BOTH real (file:line + snippet matches the actual file) AND relevant. Also spot-check the [ref:] citations in the Significant decisions table.' },
  { key: 'security', type: 'plan-security-lens-reviewer', extra: 'Focus: security at plan level — bearer-secret handling in the cockpit spawn path (tmux -e claim), OpenAI API key custody in the vault, new /v1/models endpoint auth, fail-closed gate completeness, anything the plan misses about exposing an OpenAI-billed credential through an Anthropic-shaped proxy.' },
  { key: 'decisions', type: 'plan-decisions-reviewer', extra: 'Focus: the "## Significant decisions" table — challenge each row for real alternative-weighing, concrete why-it-matters, and post-hoc rationalisation. Locked operator decisions are inputs, not targets.' },
]

const FINDINGS_SCHEMA = {
  type: 'object',
  required: ['findings'],
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        required: ['severity', 'likelihood', 'section', 'summary'],
        properties: {
          severity: { type: 'string', enum: ['P0', 'P1', 'P2', 'P3'] },
          likelihood: { type: 'string', enum: ['likely', 'possible', 'unlikely', 'remote'] },
          section: { type: 'string', description: 'plan section the finding anchors to' },
          summary: { type: 'string', description: 'one-sentence defect statement' },
          evidence: { type: 'string', description: 'file:line or quoted plan text supporting the claim' },
          suggestion: { type: 'string', description: 'smallest concrete fix' },
        },
      },
    },
    overall_note: { type: 'string', description: 'one-line overall verdict from this lens' },
  },
}

phase('Review')
const results = await parallel(REVIEWERS.map((r) => () =>
  agent(`${COMMON}\n\nYOUR LENS (${r.key}): ${r.extra}`, {
    label: `review:${r.key}`,
    phase: 'Review',
    agentType: r.type,
    schema: FINDINGS_SCHEMA,
  }).then((out) => ({ lens: r.key, ...out }))
))

return { reviews: results.filter(Boolean) }
